126		/**
127		 * Sets combined matrix basing on camera position, rotation and zoom
128		 * 
129		 * <p> Same as calling:
130		 * {@code setCombinedMatrix(
131		 *                camera.combined,
132		 *                camera.position.x,
133		 *                camera.position.y,
134		 *                camera.viewportWidth * camera.zoom,
135		 *                camera.viewportHeight * camera.zoom );}
136		 * 
137		 * @see #setCombinedMatrix(Matrix4)
138		 * @see #setCombinedMatrix(Matrix4, float, float, float, float)
139		 */
140		public void setCombinedMatrix(OrthographicCamera camera) {
141			this.setCombinedMatrix(
142					camera.combined,
143					camera.position.x,
144					camera.position.y,
145					camera.viewportWidth * camera.zoom,
146					camera.viewportHeight * camera.zoom);
147		}
