149		/**
150		 * Sets combined camera matrix.
151		 * 
152		 * <p>Matrix must be set to work in box2d coordinates, it will be copied
153		 * and used for culling and rendering. Remember to update it if camera
154		 * changes. This will work with rotated cameras.
155		 * 
156		 * <p>NOTE: Matrix4 is assumed to be orthogonal for culling
157		 * and directional lights.
158		 * 
159		 * <p>If any problems detected use the
160		 * {@link #setCombinedMatrix(Matrix4, float, float, float, float)} instead
161		 * 
162		 * @param combined
163		 *            matrix that include projection and translation matrices
164		 * 
165		 * @see #setCombinedMatrix(OrthographicCamera)
166		 * @see #setCombinedMatrix(Matrix4, float, float, float, float)
167		 */
168		public void setCombinedMatrix(Matrix4 combined) {
169			System.arraycopy(combined.val, 0, this.combined.val, 0, 16);
170	
171			// updateCameraCorners
172			float invWidth = combined.val[Matrix4.M00];
173	
174			final float halfViewPortWidth = 1f / invWidth;
175			final float x = -halfViewPortWidth * combined.val[Matrix4.M03];
176			x1 = x - halfViewPortWidth;
177			x2 = x + halfViewPortWidth;
178	
179			float invHeight = combined.val[Matrix4.M11];
180	
181			final float halfViewPortHeight = 1f / invHeight;
182			final float y = -halfViewPortHeight * combined.val[Matrix4.M13];
183			y1 = y - halfViewPortHeight;
184			y2 = y + halfViewPortHeight;
185	
186		}
187	
188		/**
189		 * Sets combined camera matrix.
190		 * 
191		 * <p>Matrix must be set to work in box2d coordinates, it will be copied
192		 * and used for culling and rendering. Remember to update it if camera
193		 * changes. This will work with rotated cameras.
194		 * 
195		 * @param combined
196		 *            matrix that include projection and translation matrices
197		 * @param x
198		 *            combined matrix position
199		 * @param y
200		 *            combined matrix position
201		 * @param viewPortWidth
202		 *            NOTE!! use actual size, remember to multiple with zoom value
203		 *            if pulled from OrthoCamera
204		 * @param viewPortHeight
205		 *            NOTE!! use actual size, remember to multiple with zoom value
206		 *            if pulled from OrthoCamera
207		 * 
