209		 * @see #setCombinedMatrix(Matrix4)
210		 */
211		public void setCombinedMatrix(Matrix4 combined, float x, float y,
212				float viewPortWidth, float viewPortHeight) {
213			
214			System.arraycopy(combined.val, 0, this.combined.val, 0, 16);
215			// updateCameraCorners
216			final float halfViewPortWidth = viewPortWidth * 0.5f;
217			x1 = x - halfViewPortWidth;
218			x2 = x + halfViewPortWidth;
219	
220			final float halfViewPortHeight = viewPortHeight * 0.5f;
221			y1 = y - halfViewPortHeight;
222			y2 = y + halfViewPortHeight;
223		}
224	
225		/**
226		 * Utility method to check if light is on the screen
227		 * @param x      - light center x-coord 
228		 * @param y      - light center y-coord 
229		 * @param radius - maximal light distance
230		 * 
231		 * @return true if camera screen intersects or contains provided
232		 * light, represented by circle/box area
233		 */
234		public boolean intersect(float x, float y, float radius) {
235			return (x1 < (x + radius) && x2 > (x - radius) &&
236					y1 < (y + radius) && y2 > (y - radius));
237		}
238	
239		/**
240		 * Updates and renders all active lights.
241		 * 
242		 * <p><b>NOTE!</b> Remember to set combined matrix before this method.
243		 * 
244		 * <p>Don't call this inside of any begin/end statements.
245		 * Call this method after you have rendered background but before UI.
246		 * Box2d bodies can be rendered before or after depending how you want
247		 * the x-ray lights to interact with them.
248		 * 
249		 * @see #update()
250		 * @see #render()
251		 */
252		public void updateAndRender() {
253			update();
254			render();
255		}
256	
257		/**
258		 * Manual update method for all active lights.
259		 * 
260		 * <p>Use this if you have less physics steps than rendering steps.
261		 * 
262		 * @see #updateAndRender()
263		 * @see #render()
264		 */
265		public void update() {
266			for (BaseLight light : lightList) {
267				light.update();
268			}
269		}
270	
271		public abstract void render();
272	
273		/**
274		 * Checks whether the given point is inside of any light volume
275		 * 
276		 * @return true if point is inside of any light volume
277		 */
278		public boolean pointAtLight(float x, float y) {
279			for (BaseLight light : lightList) {
280				if (light.contains(x, y)) return true;
281			}
282			return false;
283		}
284	
285		/**
286		 * Checks whether the given point is outside of all light volumes
287		 * 
288		 * @return true if point is NOT inside of any light volume
289		 */
290		public boolean pointAtShadow(float x, float y) {
291			for (BaseLight light : lightList) {
292				if (light.contains(x, y)) return false;
293			}
294			return true;
295		}
296	
297		/**
298		 * Disposes all this rayHandler lights and resources
299		 */
300		public void dispose() {
301			removeAll();
302			if (lightShader != null) lightShader.dispose();
303		}
304		
305		void add(BaseLight light) {
306			if (light.active) {
307				lightList.add(light);
308			} else {
309				disabledLights.add(light);
310			}
311		}
312		
313		void remove(BaseLight light) {
314			if (light.active) {
315				lightList.removeValue(light, false);
316			} else {
317				disabledLights.removeValue(light, false);
318			}
319		}
320	
321		/**
322		 * Removes and disposes both all active and disabled lights
323		 */
324		public void removeAll() {
325			for (BaseLight light : lightList) {
326				light.dispose();
327			}
328			lightList.clear();
329	
330			for (BaseLight light : disabledLights) {
331				light.dispose();
332			}
333			disabledLights.clear();
334		}	
335	 
336		/**
337		 * Enables/disables culling.
338		 * 
339		 * <p>This save CPU and GPU time when the world is bigger than the screen.
340		 * 
341		 * <p>Default = true
342		 */
343		public void setCulling(boolean culling) {
344			this.culling = culling;
345		}
346		
347		public boolean isCulling() {
348			return culling;
349		}
350	
351		/**
352		 * Enables/disables Gaussian blur.
353		 * 
354		 * <p>This make lights much more softer and realistic look but cost some
355		 * precious shader time. With default FBO size on android cost around 1ms.
356		 * 
357		 * <p>Default = true
358		 * 
359		 * @see #setBlurNum(int)
360		 */
361		public void setBlur(boolean blur) {
362			this.blur = blur;
363		}
364		
365		public boolean isBlur() {
366			return blur;
367		}
368		
369		/**
370		 * Sets number of Gaussian blur passes.
371		 * 
372		 * <p>Blurring can be pretty heavy weight operation, 1-3 should be safe.
373		 * Setting this to 0 is the same as disabling it.
374		 * 
375		 * <p>Default = 1
376		 * 
377		 * @see #setBlur(boolean)
378		 */
379		public void setBlurNum(int blurNum) {
380			this.lightBlurPasses = blurNum;
381		}
382		
383		public int getBlurNum() {
384			return lightBlurPasses;
385		}
386	
387		/**
388		 * Enables/disables shadows
389		 */
390		public void setShadows(boolean shadows) {
391			this.shadows = shadows;
392		}
393		
394		public boolean isShadows() {
395			return shadows;
396		}
397	
398		/**
399		 * Sets ambient light brightness. Specifies shadows brightness.
400		 * <p>Default = 0
401		 * 
402		 * @param ambientLight
403		 *            shadows brightness value, clamped to [0f; 1f]
404		 * 
405		 * @see #setAmbientLight(Color)
406		 * @see #setAmbientLight(float, float, float, float)
407		 */
408		public void setAmbientLight(float ambientLight) {
409			this.ambientLight.a = MathUtils.clamp(ambientLight, 0f, 1f);
410		}
411	
412		/**
413		 * Sets ambient light color.
414		 * Specifies how shadows colored and their brightness.
415		 * 
416		 * <p>Default = Color(0, 0, 0, 0)
417		 * 
418		 * @param r
419		 *            shadows color red component
420		 * @param g
421		 *            shadows color green component
422		 * @param b
423		 *            shadows color blue component
424		 * @param a
425		 *            shadows brightness component
426		 * 
427		 * @see #setAmbientLight(float)
428		 * @see #setAmbientLight(Color)
429		 */
430		public void setAmbientLight(float r, float g, float b, float a) {
431			this.ambientLight.set(r, g, b, a);
432		}
433	
434		/**
435		 * Sets ambient light color.
436		 * Specifies how shadows colored and their brightness.
437		 * 
438		 * <p>Default = Color(0, 0, 0, 0)
439		 * 
440		 * @param ambientLightColor
441		 * 	          color whose RGB components specify the shadows coloring and
442		 *            alpha specify shadows brightness 
443		 * 
444		 * @see #setAmbientLight(float)
445		 * @see #setAmbientLight(float, float, float, float)
446		 */
447		public void setAmbientLight(Color ambientLightColor) {
448			this.ambientLight.set(ambientLightColor);
449		}
450		
451		public Color getAmbientLight() {
452			return tmpColor.set(ambientLight);
453		}
454	
455		/**
456		 * Sets physics world to work with for this rayHandler
457		 */
458		public void setWorld(World world) {
459			this.world = world;
460		}
461		
462		public World getWorld() {
463			return world;
464		}
465	
466		/**
467		 * Sets rendering to custom viewport with specified position and size
468		 * <p>Note: you will be responsible for update of viewport via this method
469		 * in case of any changes (on resize)
470		 */
471		public void useCustomViewport(int x, int y, int width, int height) {
472			customViewport = true;
473			viewportX = x;
474			viewportY = y;
475			viewportWidth = width;
476			viewportHeight = height;
477		}
478		
479		/**
480		 * Sets rendering to default viewport
481		 * 
482		 * <p>0, 0, Gdx.graphics.getWidth(), Gdx.graphics.getHeight()
483		 */
484		public void useDefaultViewport() {
485			customViewport = false;
486		}
487		
488		public int getLigtsRenderedLastFrame() {
489			return lightsRenderedLastFrame;
490		}
491		
492		/**
493		 * Enables/disables lightMap automatic rendering.
494		 * 
495		 * <p>If set to false user needs to use the {@link #getLightMapTexture()}
496		 * and render that or use it as a light map when rendering. Example shader
497		 * for spriteBatch is given. This is faster way to do if there is not that
498		 * much overdrawing or if just couple object need light/shadows.
499		 * 
500		 * <p>Default = true
501		 */
502		public void setLightMapRendering(boolean isAutomatic) {
503			lightMap.lightMapDrawingDisabled = !isAutomatic;
504		}
505	
506		/**
507		 * Expert functionality
508		 * 
509		 * @return Texture that contain lightmap texture that can be used as light
510		 *         texture in your shaders
511		 */
512		public Texture getLightMapTexture() {
513			return lightMap.frameBuffer.getColorBufferTexture();
514		}
515	
516		/**
517		 * Expert functionality, no support given
518		 * 
519		 * @return FrameBuffer that contains lightMap
520		 */
521		public FrameBuffer getLightMapBuffer() {
522			return lightMap.frameBuffer;
523		}
524	
525	}
