1	package box2dLight.p3d;
2	
3	import box2dLight.PositionalLight;
4	
5	import com.badlogic.gdx.graphics.Color;
6	import com.badlogic.gdx.graphics.GL20;
7	import com.badlogic.gdx.graphics.Mesh;
8	import com.badlogic.gdx.graphics.Mesh.VertexDataType;
9	import com.badlogic.gdx.graphics.VertexAttribute;
10	import com.badlogic.gdx.graphics.VertexAttributes.Usage;
11	import com.badlogic.gdx.math.Intersector;
12	import com.badlogic.gdx.math.MathUtils;
13	import com.badlogic.gdx.physics.box2d.Body;
14	import com.badlogic.gdx.physics.box2d.ChainShape;
15	import com.badlogic.gdx.physics.box2d.CircleShape;
16	import com.badlogic.gdx.physics.box2d.EdgeShape;
17	import com.badlogic.gdx.physics.box2d.Fixture;
18	import com.badlogic.gdx.physics.box2d.PolygonShape;
19	import com.badlogic.gdx.physics.box2d.Shape;
20	import com.badlogic.gdx.physics.box2d.Shape.Type;
21	
22	/**
23	 * Light shaped as a circle with given radius
24	 * 
25	 * <p>Extends {@link PositionalLight}
26	 * 
27	 * @author rinold
28	 */
29	public class P3dPointLight extends P3dPositionalLight {
30	
31		/**
32		 * Creates light shaped as a circle with default radius (15f), color and
33		 * position (0f, 0f)
34		 * 
35		 * @param lightManager
36		 *            not {@code null} instance of P3dLightManager
37		 * @param rays
38		 *            number of rays - more rays make light to look more realistic
39		 *            but will decrease performance, can't be less than MIN_RAYS
40		 */
41		public P3dPointLight(P3dLightManager lightManager, int rays) {
42			this(lightManager, rays, DefaultColor, 15f, 0f, 0f);
43		}
44		
45		/**
46		 * Creates light shaped as a circle with given radius
47		 * 
48		 * @param lightManager
49		 *            not {@code null} instance of P3dLightManager
50		 * @param rays
51		 *            number of rays - more rays make light to look more realistic
52		 *            but will decrease performance, can't be less than MIN_RAYS
53		 * @param color
54		 *            color, set to {@code null} to use the default color
55		 * @param distance
56		 *            distance of light
57		 * @param x
58		 *            horizontal position in world coordinates
59		 * @param y
60		 *            vertical position in world coordinates
61		 */
62		public P3dPointLight(P3dLightManager lightManager, int rays, Color color,
63				float distance, float x, float y) {
64			super(lightManager, rays, color, distance, x, y, 0f);
65		}
66		
67		@Override
68		public void update () {
69			updateBody();
70			if (dirty) {
71				setEndPoints();
72			}
73			
74			if (cull()) return;
75			if (staticLight && !dirty) return;
76			
77			dirty = false;
78			updateMesh();
79			prepeareFixtureData();
80			updateDynamicShadowMeshes();
81		}
82		
83		@Override
84		public void dynamicShadowRender () {
85			for (int i = 0; i < activeShadows; i++) {
86				Mesh m = dynamicShadowMeshes.get(i);
87				m.render(shader, GL20.GL_TRIANGLE_STRIP);
88			}
89		}
90		
91		protected void updateDynamicShadowMeshes() {
92			activeShadows = 0;
93			for (Fixture fixture : affectedFixtures) {
94				P3dData data = (P3dData)fixture.getUserData();
95				if (data == null || fixture.isSensor()) continue;
96				
97				int size = 0;
98				float l = 0f;
99				
100				Shape fixtureShape = fixture.getShape();
101				Type type = fixtureShape.getType();
102				Body body = fixture.getBody();
103				center.set(body.getWorldCenter());
104				
105				if (type == Type.Polygon || type == Type.Chain) {
106					boolean isPolygon = (type == Type.Polygon);
107					ChainShape cShape = isPolygon ?
108							null : (ChainShape)fixtureShape;
109					PolygonShape pShape = isPolygon ?
110							(PolygonShape)fixtureShape : null;
111					int vertexCount = isPolygon ?
112							pShape.getVertexCount() : cShape.getVertexCount();
113					int minN = -1;
114					int maxN = -1;
115					int minDstN = -1;
116					float minDst = Float.POSITIVE_INFINITY;
117					boolean hasGasp = false;
118					tmpVerts.clear();
119					for (int n = 0; n < vertexCount; n++) {
120						if (isPolygon) {
121							pShape.getVertex(n, tmpVec);
122						} else {
123							cShape.getVertex(n, tmpVec);
124						}
125						tmpVec.set(body.getWorldPoint(tmpVec));
126						tmpVerts.add(tmpVec.cpy());
127						tmpEnd.set(tmpVec).sub(start).limit2(0.0001f).add(tmpVec);
128						if (fixture.testPoint(tmpEnd)) {
129							if (minN == -1) minN = n;
130							maxN = n;
131							hasGasp = true;
132							continue;
133						}
134						
135						float currDist = tmpVec.dst2(start);
136						if (currDist < minDst) {
137							minDst = currDist;
138							minDstN = n;
139						}
140					}
141					
142					ind.clear();
143					if (!hasGasp) {
144						tmpVec.set(tmpVerts.get(minDstN));
145						for (int n = minDstN; n < vertexCount; n++) {
146							ind.add(n);
147						}
148						for (int n = 0; n < minDstN; n++) {
149							ind.add(n);
150						}
151						if (Intersector.pointLineSide(start, center, tmpVec) > 0) {
152							ind.reverse();
153							ind.insert(0, ind.pop());
154						}
155					} else if (minN == 0 && maxN == vertexCount - 1) {
156						for (int n = maxN - 1; n > minN; n--) {
157							ind.add(n);
158						}
159					} else {
160						for (int n = minN - 1; n > -1; n--) {
161							ind.add(n);
162						}
163						for (int n = vertexCount - 1; n > maxN ; n--) {
164							ind.add(n);
165						}
166					}
167					
168					for (int n : ind.toArray()) {
169						tmpVec.set(tmpVerts.get(n));
170						
171						float dst = tmpVec.dst(start);
172						l = data.getLimit(dst, height, distance);
173						tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
174						float f1 = 1f - dst / distance;
175						float f2 = 1f - (dst + l) / distance;
176						
177						segments[size++] = tmpVec.x;
178						segments[size++] = tmpVec.y;
179						segments[size++] = colorF;
180						segments[size++] = f1;
181						
182						segments[size++] = tmpEnd.x;
183						segments[size++] = tmpEnd.y;
184						segments[size++] = colorF;
185						segments[size++] = f2;
186					}
187				} else if (type == Type.Circle) {
188					CircleShape shape = (CircleShape)fixtureShape;
189					float r = shape.getRadius();
190					float dst = tmpVec.set(center).dst(start);
191					float a = (float) Math.acos(r/dst);
192					l = data.getLimit(dst, height, distance);
193					float f1 = 1f - dst / distance;
194					float f2 = 1f - (dst + l) / distance;
195					
196					tmpVec.set(start).sub(center).clamp(r, r).rotateRad(a);
197					tmpStart.set(center).add(tmpVec);
198					
199					float angle = (MathUtils.PI2 - 2f * a) /
200							P3dLightManager.CIRCLE_APPROX_POINTS;
201					for (int k = 0; k < P3dLightManager.CIRCLE_APPROX_POINTS; k++) {
202						tmpStart.set(center).add(tmpVec);
203						segments[size++] = tmpStart.x;
204						segments[size++] = tmpStart.y;
205						segments[size++] = colorF;
206						segments[size++] = f1;
207						
208						tmpEnd.set(tmpStart).sub(start).setLength(l).add(tmpStart);
209						segments[size++] = tmpEnd.x;
210						segments[size++] = tmpEnd.y;
211						segments[size++] = colorF;
212						segments[size++] = f2;
213						
214						tmpVec.rotateRad(angle);
215					}
216				} else if (type == Type.Edge) {
217					EdgeShape shape = (EdgeShape)fixtureShape;
218					
219					shape.getVertex1(tmpVec);
