2	package box2dLight;
3	
4	import com.badlogic.gdx.Gdx;
5	import com.badlogic.gdx.graphics.*;
6	import com.badlogic.gdx.graphics.Mesh.VertexDataType;
7	import com.badlogic.gdx.graphics.VertexAttributes.Usage;
8	import com.badlogic.gdx.math.Intersector;
