10	import com.badlogic.gdx.math.Vector2;
11	import com.badlogic.gdx.physics.box2d.*;
12	
13	/**
14	 * Abstract base class for all positional lights
15	 * 
16	 * <p>Extends {@link Light}
17	 * 
18	 * @author kalle_h
19	 */
20	public abstract class PositionalLight extends Light {
21	
22		Color tmpColor = new Color();
23	
24		protected final Vector2 tmpEnd = new Vector2();
25		protected final Vector2 start = new Vector2();
26		
27		protected Body body;
28		protected float bodyOffsetX;
29		protected float bodyOffsetY;
30		protected float bodyAngleOffset;
31		
32		protected float sin[];
33		protected float cos[];
34	
35		protected float endX[];
36		protected float endY[];
37		
38		/** 
39		 * Creates new positional light and automatically adds it to the specified
40		 * {@link RayHandler} instance.
41		 * 
42		 * @param rayHandler
43		 *            not null instance of RayHandler
44		 * @param rays
45		 *            number of rays - more rays make light to look more realistic
46		 *            but will decrease performance, can't be less than MIN_RAYS
47		 * @param color
48		 *            light color
49		 * @param distance
50		 *            light distance (if applicable)
51		 * @param x
52		 *            horizontal position in world coordinates
53		 * @param y
54		 *            vertical position in world coordinates
55		 * @param directionDegree
56		 *            direction in degrees (if applicable) 
57		 */
58		public PositionalLight(RayHandler rayHandler, int rays, Color color, float distance, float x, float y, float directionDegree) {
59			super(rayHandler, rays, color, distance, directionDegree);
60			start.x = x;
61			start.y = y;
62	
63			Mesh.VertexDataType vertexDataType = Mesh.VertexDataType.VertexArray;
64			if (Gdx.gl30 != null) {
65				vertexDataType = VertexDataType.VertexBufferObjectWithVAO;
66			}
67			lightMesh = new Mesh(vertexDataType, false, vertexNum, 0, new VertexAttribute(Usage.Position, 2,
68				"vertex_positions"), new VertexAttribute(Usage.ColorPacked, 4, "quad_colors"),
69				new VertexAttribute(Usage.Generic, 1, "s"));
70			softShadowMesh = new Mesh(vertexDataType, false, vertexNum * 2, 0, new VertexAttribute(Usage.Position, 2,
71				"vertex_positions"), new VertexAttribute(Usage.ColorPacked, 4, "quad_colors"),
72				new VertexAttribute(Usage.Generic, 1, "s"));
73			setMesh();
74		}
75		
76		@Override
77		public void update() {
78			updateBody();
79			
80			if (cull()) return;
81			if (staticLight && !dirty) return;
82			
83			dirty = false;
84			updateMesh();
85		}
86		
87		@Override
88		public void render() {
89			if (lightHandler.isCulling() && culled) return;
90	
91			rayHandler.lightRenderedLastFrame++;
92			lightMesh.render(rayHandler.lightShader, GL20.GL_TRIANGLE_FAN, 0, vertexNum);
93	
94			if (soft && !xray && !rayHandler.pseudo3d) {
95				softShadowMesh.render(
96						rayHandler.lightShader,
97						GL20.GL_TRIANGLE_STRIP,
98						0, (vertexNum - 1) * 2);
99			}
100		}
101		
102		@Override
103		public void attachToBody(Body body) {
