231			final float cos = MathUtils.cos(angle);
232			final float sin = MathUtils.sin(angle);
233			final float dX = bodyOffsetX * cos - bodyOffsetY * sin;
234			final float dY = bodyOffsetX * sin + bodyOffsetY * cos;
235			start.x = vec.x + dX;
236			start.y = vec.y + dY;
237			setDirection(bodyAngleOffset + angle * MathUtils.radiansToDegrees);
238		}
