242				m_index = i;
243				f[i] = 1f;
244				tmpEnd.x = endX[i] + start.x;
245				mx[i] = tmpEnd.x;
246				tmpEnd.y = endY[i] + start.y;
247				my[i] = tmpEnd.y;
