263			// ray starting point
264			int size = 0;
265	
266			segments[size++] = start.x;
267			segments[size++] = start.y;
268			segments[size++] = colorF;
269			segments[size++] = 1;
270			// rays ending points.
271			for (int i = 0; i < rayNum; i++) {
272				segments[size++] = mx[i];
273				segments[size++] = my[i];
274				segments[size++] = colorF;
275				segments[size++] = 1 - f[i];
276			}
277			lightMesh.setVertices(segments, 0, size);
278	
279			if (!soft || xray || rayHandler.pseudo3d) return;
280	
281			size = 0;
282			// rays ending points.
283			for (int i = 0; i < rayNum; i++) {
284				segments[size++] = mx[i];
285				segments[size++] = my[i];
286				segments[size++] = colorF;
287				final float s = (1 - f[i]);
288				segments[size++] = s;
289				segments[size++] = mx[i] + s * softShadowLength * cos[i];
290				segments[size++] = my[i] + s * softShadowLength * sin[i];
291				segments[size++] = zeroColorBits;
292				segments[size++] = 0f;
293			}
294			softShadowMesh.setVertices(segments, 0, size);
295		}
