297		protected void updateDynamicShadowMeshes() {
298			int meshInd = 0;
299			float colBits = rayHandler.ambientLight.toFloatBits();
300			for (Fixture fixture : affectedFixtures) {
301				LightData data = (LightData)fixture.getUserData();
302				if (data == null || fixture.isSensor()) continue;
303	
304				int size = 0;
305				float l;
306	
307				Shape fixtureShape = fixture.getShape();
308				Shape.Type type = fixtureShape.getType();
309				Body body = fixture.getBody();
310				center.set(body.getWorldCenter());
311	
312				if (type == Shape.Type.Polygon || type == Shape.Type.Chain) {
313					boolean isPolygon = (type == Shape.Type.Polygon);
314					ChainShape cShape = isPolygon ?
315							null : (ChainShape)fixtureShape;
316					PolygonShape pShape = isPolygon ?
317							(PolygonShape)fixtureShape : null;
318					int vertexCount = isPolygon ?
319							pShape.getVertexCount() : cShape.getVertexCount();
320					int minN = -1;
321					int maxN = -1;
322					int minDstN = -1;
323					float minDst = Float.POSITIVE_INFINITY;
324					boolean hasGasp = false;
325					tmpVerts.clear();
326					for (int n = 0; n < vertexCount; n++) {
327						if (isPolygon) {
328							pShape.getVertex(n, tmpVec);
329						} else {
330							cShape.getVertex(n, tmpVec);
331						}
332						tmpVec.set(body.getWorldPoint(tmpVec));
333						tmpVerts.add(tmpVec.cpy());
334						tmpEnd.set(tmpVec).sub(start).limit2(0.0001f).add(tmpVec);
335						if (fixture.testPoint(tmpEnd)) {
336							if (minN == -1) minN = n;
337							maxN = n;
338							hasGasp = true;
339							continue;
340						}
341	
342						float currDist = tmpVec.dst2(start);
343						if (currDist < minDst) {
344							minDst = currDist;
345							minDstN = n;
346						}
347					}
348	
349					ind.clear();
350					if (!hasGasp) {
351						tmpVec.set(tmpVerts.get(minDstN));
352						for (int n = minDstN; n < vertexCount; n++) {
353							ind.add(n);
354						}
355						for (int n = 0; n < minDstN; n++) {
356							ind.add(n);
357						}
358						if (Intersector.pointLineSide(start, center, tmpVec) > 0) {
359							ind.reverse();
360							ind.insert(0, ind.pop());
361						}
362					} else if (minN == 0 && maxN == vertexCount - 1) {
363						for (int n = maxN - 1; n > minN; n--) {
364							ind.add(n);
365						}
366					} else {
367						for (int n = minN - 1; n > -1; n--) {
368							ind.add(n);
369						}
370						for (int n = vertexCount - 1; n > maxN ; n--) {
371							ind.add(n);
372						}
373					}
374	
375					boolean contained = false;
376					for (int n : ind.toArray()) {
377						tmpVec.set(tmpVerts.get(n));
378						if (contains(tmpVec.x, tmpVec.y)){
379							contained = true;
380							break;
381						}
382					}
383	
384					if (!contained)
385						continue;
386	
387					for (int n : ind.toArray()) {
388						tmpVec.set(tmpVerts.get(n));
389	
390						float dst = tmpVec.dst(start);
391						l = data.getLimit(dst, pseudo3dHeight, distance);
392						tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
393	
394						float f1 = 1f - dst / distance;
395						float f2 = 1f - (dst + l) / distance;
396	
397						tmpColor.set(Color.BLACK);
398						float startColBits = rayHandler.shadowColorInterpolation ?
399								tmpColor.lerp(rayHandler.ambientLight, f1).toFloatBits() :
400								oneColorBits;
401						tmpColor.set(Color.WHITE);
402						float endColBits = rayHandler.shadowColorInterpolation ?
403								tmpColor.lerp(rayHandler.ambientLight, f2).toFloatBits() :
404								colBits;
405	
406						segments[size++] = tmpVec.x;
407						segments[size++] = tmpVec.y;
408						segments[size++] = startColBits;
409						segments[size++] = f1;
410	
411						segments[size++] = tmpEnd.x;
412						segments[size++] = tmpEnd.y;
413						segments[size++] = endColBits;
414						segments[size++] = f2;
415					}
416				} else if (type == Shape.Type.Circle) {
417					CircleShape shape = (CircleShape)fixtureShape;
418					float r = shape.getRadius();
419					if (!contains(tmpVec.set(center).add(r, r)) && !contains(tmpVec.set(center).add(-r, -r))
420							&& !contains(tmpVec.set(center).add(r, -r)) && !contains(tmpVec.set(center).add(-r, r))) {
421						continue;
422					}
423	
424					float dst = tmpVec.set(center).dst(start);
425					float a = (float) Math.acos(r/dst);
426					l = data.getLimit(dst, pseudo3dHeight, distance);
427					float f1 = 1f - dst / distance;
428					float f2 = 1f - (dst + l) / distance;
429					tmpColor.set(Color.BLACK);
430					float startColBits = rayHandler.shadowColorInterpolation ?
431							tmpColor.lerp(rayHandler.ambientLight, f1).toFloatBits() :
432							oneColorBits;
433					tmpColor.set(Color.WHITE);
434					float endColBits = rayHandler.shadowColorInterpolation ?
435							tmpColor.lerp(rayHandler.ambientLight, f2).toFloatBits() :
436							colBits;
437	
438					tmpVec.set(start).sub(center).clamp(r, r).rotateRad(a);
439					tmpStart.set(center).add(tmpVec);
440	
441					float angle = (MathUtils.PI2 - 2f * a) /
442							RayHandler.CIRCLE_APPROX_POINTS;
443					for (int k = 0; k < RayHandler.CIRCLE_APPROX_POINTS; k++) {
444						tmpStart.set(center).add(tmpVec);
445						segments[size++] = tmpStart.x;
446						segments[size++] = tmpStart.y;
447						segments[size++] = startColBits;
448						segments[size++] = f1;
449	
450						tmpEnd.set(tmpStart).sub(start).setLength(l).add(tmpStart);
451						segments[size++] = tmpEnd.x;
452						segments[size++] = tmpEnd.y;
453						segments[size++] = endColBits;
454						segments[size++] = f2;
455	
456						tmpVec.rotateRad(angle);
457					}
458				} else if (type == Shape.Type.Edge) {
459					EdgeShape shape = (EdgeShape)fixtureShape;
460	
461					shape.getVertex1(tmpVec);
462					tmpVec.set(body.getWorldPoint(tmpVec));
463					if (!contains(tmpVec)) {
464						continue;
465					}
466					float dst = tmpVec.dst(start);
467					l = data.getLimit(dst, pseudo3dHeight, distance);
468					float f1 = 1f - dst / distance;
469					float f2 = 1f - (dst + l) / distance;
470					tmpColor.set(Color.BLACK);
471					float startColBits = rayHandler.shadowColorInterpolation ?
472							tmpColor.lerp(rayHandler.ambientLight, f1).toFloatBits() :
473							oneColorBits;
474					tmpColor.set(Color.WHITE);
475					float endColBits = rayHandler.shadowColorInterpolation ?
476							tmpColor.lerp(rayHandler.ambientLight, f2).toFloatBits() :
477							colBits;
478	
479					segments[size++] = tmpVec.x;
480					segments[size++] = tmpVec.y;
481					segments[size++] = startColBits;
482					segments[size++] = f1;
483	
484					tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
485					segments[size++] = tmpEnd.x;
486					segments[size++] = tmpEnd.y;
487					segments[size++] = endColBits;
488					segments[size++] = f2;
489	
490					shape.getVertex2(tmpVec);
491					tmpVec.set(body.getWorldPoint(tmpVec));
492					if (!contains(tmpVec)) {
493						continue;
494					}
495					dst = tmpVec.dst(start);
496					l = data.getLimit(dst, pseudo3dHeight, distance);
497					f1 = 1f - dst / distance;
498					f2 = 1f - (dst + l) / distance;
499					tmpColor.set(Color.BLACK);
500					startColBits = rayHandler.shadowColorInterpolation ?
501							tmpColor.lerp(rayHandler.ambientLight, f1).toFloatBits() :
502							oneColorBits;
503					tmpColor.set(Color.WHITE);
504					endColBits = rayHandler.shadowColorInterpolation ?
505							tmpColor.lerp(rayHandler.ambientLight, f2).toFloatBits() :
506							colBits;
507	
508					segments[size++] = tmpVec.x;
509					segments[size++] = tmpVec.y;
510					segments[size++] = startColBits;
511					segments[size++] = f1;
512	
513					tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
514					segments[size++] = tmpEnd.x;
515					segments[size++] = tmpEnd.y;
516					segments[size++] = endColBits;
517					segments[size++] = f2;
518				}
519	
520				Mesh mesh = null;
521				if (meshInd >= dynamicShadowMeshes.size) {
522					mesh = new Mesh(
523							Mesh.VertexDataType.VertexArray, false, RayHandler.MAX_SHADOW_VERTICES, 0,
524							new VertexAttribute(VertexAttributes.Usage.Position, 2, "vertex_positions"),
525							new VertexAttribute(VertexAttributes.Usage.ColorPacked, 4, "quad_colors"),
526							new VertexAttribute(VertexAttributes.Usage.Generic, 1, "s"));
527					dynamicShadowMeshes.add(mesh);
528				} else {
529					mesh = dynamicShadowMeshes.get(meshInd);
530				}
531				mesh.setVertices(segments, 0, size);
532				meshInd++;
533			}
534			dynamicShadowMeshes.truncate(meshInd);
535		}
