151		 */
152		public abstract void setPosition(float x, float y);
153	
154		/**
155		 * Sets light starting position
156		 *
157		 * @see #setPosition(float, float)
158		 */
159		public abstract void setPosition(Vector2 position);
160	
161		/**
162		 * @return horizontal starting position of light in world coordinates
163		 */
164		public abstract float getX();
165	
166		/**
167		 * @return vertical starting position of light in world coordinates
168		 */
169		public abstract float getY();
170	
171		/**
172		 * @return starting position of light in world coordinates
173		 *         <p>NOTE: changing this vector does nothing
174		 */
175		public Vector2 getPosition() {
176			return tmpPosition;
