179		/**
180		 * Sets light color
181		 *
182		 * <p>NOTE: you can also use colorless light with shadows, e.g. (0,0,0,1)
183		 *
184		 * @param newColor
185		 *            RGB set the color and Alpha set intensity
186		 *
187		 * @see #setColor(float, float, float, float)
188		 */
189		public void setColor(Color newColor) {
190			if (newColor != null) {
191				color.set(newColor);
192			} else {
193				color.set(DefaultColor);
194			}
195			colorF = color.toFloatBits();
196			if (staticLight) dirty = true;
