199		/**
200		 * Sets light color
201		 *
202		 * <p>NOTE: you can also use colorless light with shadows, e.g. (0,0,0,1)
203		 *
204		 * @param r
205		 *            lights color red component
206		 * @param g
207		 *            lights color green component
208		 * @param b
209		 *            lights color blue component
210		 * @param a
211		 *            lights shadow intensity
212		 *
213		 * @see #setColor(Color)
214		 */
215		public void setColor(float r, float g, float b, float a) {
216			color.set(r, g, b, a);
217			colorF = color.toFloatBits();
218			if (staticLight) dirty = true;
219		}
