221		/**
222		 * Adds light to specified RayHandler
223		 */
224		public void add(RayHandler rayHandler) {
225			this.rayHandler = rayHandler;
226			if (active) {
227				rayHandler.lightList.add(this);
228			} else {
229				rayHandler.disabledLights.add(this);
230			}
231		}
232	
233		/**
234		 * Removes light from specified RayHandler and disposes it
235		 */
236		public void remove() {
237			remove(true);
238		}
239	
240		/**
241		 * Removes light from specified RayHandler and disposes it if requested
242		 */
243		public void remove(boolean doDispose) {
244			if (active) {
245				rayHandler.lightList.removeValue(this, false);
246			} else {
247				rayHandler.disabledLights.removeValue(this, false);
248			}
249			rayHandler = null;
250			if (doDispose) dispose();
251		}
252	
253		/**
254		 * Disposes all light resources
255		 */
256		public void dispose() {
257			affectedFixtures.clear();
258			lightMesh.dispose();
259			softShadowMesh.dispose();
260			for (Mesh mesh : dynamicShadowMeshes) {
261				mesh.dispose();
262			}
263			dynamicShadowMeshes.clear();
264		}
265	
266		/**
267		 * Enables/disables softness on tips of this light beams
268		 */
269		public void setSoft(boolean soft) {
270			this.soft = soft;
271			if (staticLight) dirty = true;
272		}
