281		/**
282		 * Sets softness value for beams tips
283		 * 
284		 * <p>Default: {@code 2.5f}
285		 */
286		public void setSoftnessLength(float softShadowLength) {
287			this.softShadowLength = softShadowLength;
288			if (staticLight) dirty = true;
289		}
