306		/**
307		 * Checks if given point is inside of this light area
308		 * 
309		 * @param x - horizontal position of point in world coordinates
310		 * @param y - vertical position of point in world coordinates
311		 */
312		public boolean contains(float x, float y) {
313			return false;
314		}
