320		 *               will be ignored and will not create any shadows for this
321		 *               light. By default is set to {@code false}. 
322		 */
323		public void setIgnoreAttachedBody(boolean flag) {
324			ignoreBody = flag;
325		}
326		
327		/**
328		 * @return if the attached body fixtures will be ignored during raycasting
329		 */
330		public boolean getIgnoreAttachedBody() {
