338		/**
339		 * Internal method for mesh update depending on ray number
340		 */
341		void setRayNum(int rays) {
342			if (rays < MIN_RAYS)
343				rays = MIN_RAYS;
344	
345			rayNum = rays;
346			vertexNum = rays + 1;
347	
348			segments = new float[vertexNum * 8];
349			mx = new float[vertexNum];
350			my = new float[vertexNum];
351			f = new float[vertexNum];
352		}
353		
354		/** 
355		 * @return number of rays set for this light
356		 */
357		public int getRayNum()
358		{
359			return rayNum;
360		}
361	
362		/** Global lights filter **/
363		static private Filter globalFilterA = null;
364		/** This light specific filter **/
365		private Filter filterA = null;
366	
367		final RayCastCallback ray = new RayCastCallback() {
368			@Override
369			final public float reportRayFixture(Fixture fixture, Vector2 point,
370					Vector2 normal, float fraction) {
371				
372				if ((globalFilterA != null) && !globalContactFilter(fixture))
373					return -1;
374				
375				if ((filterA != null) && !contactFilter(fixture))
376					return -1;
377	
378				if (ignoreBody && fixture.getBody() == getBody())
379					return -1;
380	
381				// if (fixture.isSensor())
382				// return -1;
383				mx[m_index] = point.x;
384				my[m_index] = point.y;
385				f[m_index] = fraction;
386				return fraction;
387			}
388		};
389		
390		boolean contactFilter(Fixture fixtureB) {
391			Filter filterB = fixtureB.getFilterData();
392	
