322	    private boolean fixedStep(float delta) {
323	        physicsTimeLeft += delta;
324	        if (physicsTimeLeft > MAX_TIME_PER_FRAME)
325	            physicsTimeLeft = MAX_TIME_PER_FRAME;
326	
327	        boolean stepped = false;
328	        while (physicsTimeLeft >= TIME_STEP) {
329	            world.step(TIME_STEP, VELOCITY_ITERS, POSITION_ITERS);
330	            physicsTimeLeft -= TIME_STEP;
331	            stepped = true;
332	        }
333	        return stepped;
