342	        chainShape.createLoop(new Vector2[]{
343	                new Vector2(-halfWidth, 0f),
344	                new Vector2(halfWidth, 0f),
345	                new Vector2(halfWidth, viewportHeight),
346	                new Vector2(-halfWidth, viewportHeight)});
347	        BodyDef chainBodyDef = new BodyDef();
348	        chainBodyDef.type = BodyType.StaticBody;
349	        groundBody = world.createBody(chainBodyDef);
350	        groundBody.createFixture(chainShape, 0);
351	        chainShape.dispose();
352	        createBoxes();
