355	    private void createBoxes() {
356	        PolygonShape polygonShape = new PolygonShape();
357	        polygonShape.setAsBox(RADIUS, RADIUS);
358	        FixtureDef def = new FixtureDef();
359	        def.restitution = 0.9f;
360	        def.friction = 0.01f;
361	        def.shape = polygonShape;
362	        def.density = 1f;
363	        BodyDef boxBodyDef = new BodyDef();
364	        boxBodyDef.type = BodyType.DynamicBody;
365	
366	        for (int i = 0; i < BALLSNUM; i++) {
367	            // Create the BodyDef, set a random position above the
368	            // ground and create a new body
369	            boxBodyDef.position.x = -20 + (float) (Math.random() * 40);
370	            boxBodyDef.position.y = 10 + (float) (Math.random() * 15);
371	            Body boxBody = world.createBody(boxBodyDef);
372	            boxBody.createFixture(def).setUserData(new LightData(1, true));
373	            balls.add(boxBody);
374	        }
375	        polygonShape.dispose();
376	        polygonShape = new PolygonShape();
377	        polygonShape.setAsBox(RADIUS, RADIUS);
378	        def = new FixtureDef();
379	        def.restitution = 0.9f;
380	        def.friction = 0.01f;
381	        def.shape = polygonShape;
382	        def.density = 1f;
383	        boxBodyDef = new BodyDef();
384	        boxBodyDef.type = BodyType.StaticBody;
385	
386	        boxBodyDef.position.x = -20 + (float) (Math.random() * 40);
387	        boxBodyDef.position.y = 10 + (float) (Math.random() * 15);
388	        Body boxBody = world.createBody(boxBodyDef);
389	        boxBody.createFixture(def).setUserData(new LightData(2, true));
390	        staticBall = boxBody;
391	        polygonShape.dispose();
392	    }
