394	    /**
395	     * we instantiate this vector and the callback here so we don't irritate the
396	     * GC
397	     **/
398	    Vector3 testPoint = new Vector3();
399	    QueryCallback callback = new QueryCallback() {
400	        @Override
401	        public boolean reportFixture(Fixture fixture) {
402	            if (fixture.getBody() == groundBody)
403	                return true;
404	
405	            if (fixture.testPoint(testPoint.x, testPoint.y)) {
406	                hitBody = fixture.getBody();
407	                return false;
408	            } else
409	                return true;
410	        }
411	    };
