413	    @Override
414	    public boolean touchDown(int x, int y, int pointer, int newParam) {
415	        // translate the mouse coordinates to world coordinates
416	        testPoint.set(x, y, 0);
417	        camera.unproject(testPoint);
418	
419	        // ask the world which bodies are within the given
420	        // bounding box around the mouse pointer
421	        hitBody = null;
422	        world.QueryAABB(callback, testPoint.x - 0.1f, testPoint.y - 0.1f,
423	                testPoint.x + 0.1f, testPoint.y + 0.1f);
424	
425	        // if we hit something we create a new mouse joint
426	        // and attach it to the hit body.
427	        if (hitBody != null) {
428	            MouseJointDef def = new MouseJointDef();
429	            def.bodyA = groundBody;
430	            def.bodyB = hitBody;
431	            def.collideConnected = true;
432	            def.target.set(testPoint.x, testPoint.y);
433	            def.maxForce = 1000.0f * hitBody.getMass();
434	
435	            mouseJoint = (MouseJoint) world.createJoint(def);
436	            hitBody.setAwake(true);
437	        }
438	
439	        return false;
440	    }
