442	    /**
443	     * another temporary vector
444	     **/
445	    Vector2 target = new Vector2();
446	
447	    @Override
448	    public boolean touchDragged(int x, int y, int pointer) {
449	        camera.unproject(testPoint.set(x, y, 0));
450	        target.set(testPoint.x, testPoint.y);
451	        // if a mouse joint exists we simply update
452	        // the target of the joint based on the new
453	        // mouse coordinates
454	        if (mouseJoint != null) {
455	            mouseJoint.setTarget(target);
456	        }
457	        return false;
458	    }
459	
460	    @Override
461	    public boolean touchUp(int x, int y, int pointer, int button) {
462	        // if a mouse joint exists we simply destroy it
463	        if (mouseJoint != null) {
464	            world.destroyJoint(mouseJoint);
465	            mouseJoint = null;
466	        }
467	        return false;
468	    }
