476	    /**
477	     * Type of lights to use:
478	     * 0 - PointLight
479	     * 1 - ConeLight
480	     * 2 - ChainLight
481	     * 3 - DirectionalLight
482	     */
483	    int lightsType = 0;
484	
485	    @Override
486	    public boolean keyDown(int keycode) {
487	        switch (keycode) {
488	
489	            case Input.Keys.F1:
490	                if (lightsType != 0) {
491	                    initPointLights();
492	                    lightsType = 0;
493	                }
494	                return true;
495	
496	            case Input.Keys.F2:
497	                if (lightsType != 1) {
498	                    initConeLights();
499	                    lightsType = 1;
500	                }
501	                return true;
502	
503	            case Input.Keys.F3:
504	                if (lightsType != 2) {
505	                    initChainLights();
506	                    lightsType = 2;
507	                }
508	                return true;
509	
510	            case Input.Keys.F4:
511	                if (lightsType != 3) {
512	                    initDirectionalLight();
513	                    lightsType = 3;
514	                }
515	                return true;
516	
517	            case Input.Keys.F5:
518	                for (Light light : lights)
519	                    light.setColor(
520	                            MathUtils.random(),
521	                            MathUtils.random(),
522	                            MathUtils.random(),
523	                            1f);
524	                return true;
525	
526	            case Input.Keys.F6:
527	                for (Light light : lights)
528	                    light.setDistance(MathUtils.random(
529	                            LIGHT_DISTANCE * 0.5f, LIGHT_DISTANCE * 2f));
530	                return true;
531	
532	            case Input.Keys.F9:
533	                rayHandler.diffuseBlendFunc.reset();
534	                return true;
535	
536	            case Input.Keys.F10:
537	                rayHandler.diffuseBlendFunc.set(
538	                        GL20.GL_DST_COLOR, GL20.GL_SRC_COLOR);
539	                return true;
540	
541	            case Input.Keys.F11:
542	                rayHandler.diffuseBlendFunc.set(
543	                        GL20.GL_SRC_COLOR, GL20.GL_DST_COLOR);
544	                return true;
545	
546	            case Input.Keys.F12:
547	                showText = !showText;
548	                return true;
549	
550	            default:
551	                return false;
552	
553	        }
554	    }
