            val isMale = variantKey != "female"
            val isFemale = variantKey == "female"
            category.spriteSheets += LpcSpriteSheetDefinition(
                path = pngPath,
                displayName = def.name,
                explicitIsMale = isMale,
                explicitIsFemale = isFemale
            )
        }
    }
